return {
  {
    "williamboman/mason.nvim",
    cmd = "Mason",
    opts = { ui = { border = "rounded" } },
  },
  {
    "williamboman/mason-lspconfig.nvim",
    dependencies = { "mason.nvim", "nvim-lspconfig" },
    opts = {
      ensure_installed = {
        "lua_ls",
        "pyright",
        "ruff",
        "clangd",
      },
      automatic_installation = true,
      handlers = {
        function(server_name)
          require("lspconfig")[server_name].setup({})
        end,
        ["lua_ls"] = function()
          require("lspconfig").lua_ls.setup({
            settings = {
              Lua = {
                diagnostics = {
                  globals = { "vim" },
                },
              },
            },
          })
        end,
      },
    },
  },

  {
    "neovim/nvim-lspconfig",
    config = function()
      vim.api.nvim_create_autocmd("LspAttach", {
        group = vim.api.nvim_create_augroup("UserLspConfig", {}),
        callback = function(ev)
          local opts = { buffer = ev.buf, silent = true }
          vim.keymap.set("n", "gd", "<cmd>Telescope lsp_definitions<cr>", opts)
          vim.keymap.set("n", "gi", "<cmd>Telescope lsp_implementations<cr>", opts)
          vim.keymap.set("n", "gr", "<cmd>Telescope lsp_references<cr>", opts)
          vim.keymap.set("n", "K", vim.lsp.buf.hover, opts)
          vim.keymap.set("n", "<leader>rn", vim.lsp.buf.rename, opts)
          vim.keymap.set("n", "<leader>ca", vim.lsp.buf.code_action, opts)
        end,
      })
    end,
  },

  {
    "Saghen/blink.cmp",
    dependencies = { "nvim-treesitter/nvim-treesitter" },
    opts = {
      keymap = { preset = "default" },
      appearance = { use_nvim_cmp_as_default = true, nerd_font_variant = "mono" },
      completion = {
        menu = { auto_show = true, border = "rounded", winhighlight = "Normal:NormalFloat" },
        documentation = { auto_show = true, auto_show_delay_ms = 200 },
      },
      signature = { enabled = true },
    },
  },
}

return {
  {
    "stevearc/conform.nvim",
    event = { "BufWritePre" },
    cmd = { "ConformInfo" },
    keys = {
      {
        "<leader>f",
        function()
          require("conform").format({ async = true, lsp_fallback = true })
        end,
        mode = "",
        desc = "Format buffer",
      },
    },
    opts = function()
      local util = require("conform.util")

      return {
        notify_on_error = true,
        formatters_by_ft = {
          lua = { "stylua" },
          python = { "ruff_format" },
          rust = { "rustfmt" },
          c = { "clang-format" },
          cpp = { "clang-format" },
          scala = { "scalafmt" },
          go = { "goimports", "gofmt" },
          javascript = { "prettierd", "prettier", "eslint_d" },
          typescript = { "prettierd", "prettier", "eslint_d" },
          typescriptreact = { "prettierd", "prettier", "eslint_d" },
          javascriptreact = { "prettierd", "prettier", "eslint_d" },
          json = { "prettierd", "prettier" },
          yaml = { "prettierd", "prettier" },
          markdown = { "prettierd", "prettier", "mdformat" },
          sh = { "shfmt" },
          terraform = { "terraform_fmt" },

          ["_"] = { "trim_whitespace" },
        },

        format_on_save = function(bufnr)
          if util.get_buf_size(bufnr) > 256 * 1024 then
            return nil -- skip huge files
          end
          return {
            timeout_ms = 1000,
            lsp_fallback = true,
          }
        end,

        formatters = {
          prettierd = {
            condition = util.root_file({ ".prettierrc", "package.json", "prettier.config.js" }),
          },
          prettier = {
            env = {
              PRETTIERD_DEFAULT_CONFIG = vim.fn.stdpath("config") .. "/.config/prettier/config.cjs",
            },
          },
          eslint_d = {
            condition = util.root_file({ ".eslintrc", ".eslintrc.js", "package.json" }),
          },
        },
      }
    end,
  },
}

return {
  {
    "mfussenegger/nvim-dap",
    dependencies = {
      "rcarriga/nvim-dap-ui",
      "nvim-neotest/nvim-nio",
      "jay-babu/mason-nvim-dap.nvim",
      "mfussenegger/nvim-dap-python",
      "leoluz/nvim-dap-go",
    },
    keys = {
      {
        "<F5>",
        function()
          require("dap").continue()
        end,
        desc = "Debug: Continue",
      },
      {
        "<F10>",
        function()
          require("dap").step_over()
        end,
        desc = "Debug: Step Over",
      },
      {
        "<F11>",
        function()
          require("dap").step_into()
        end,
        desc = "Debug: Step Into",
      },
      {
        "<F12>",
        function()
          require("dap").step_out()
        end,
        desc = "Debug: Step Out",
      },
      {
        "<leader>b",
        function()
          require("dap").toggle_breakpoint()
        end,
        desc = "Debug: Toggle Breakpoint",
      },
    },
    config = function()
      local dap = require("dap")
      local dapui = require("dapui")

      -- ui setup
      dapui.setup()

      dap.listeners.after.event_initialized["dapui_config"] = function()
        dapui.open()
      end
      dap.listeners.before.event_terminated["dapui_config"] = function()
        dapui.close()
      end
      dap.listeners.before.event_exited["dapui_config"] = function()
        dapui.close()
      end

      local mason_nvim_dap = require("mason-nvim-dap")
      local registry = require("mason-registry")

      mason_nvim_dap.setup({
        ensure_installed = { "codelldb", "python", "delve" },
        automatic_installation = true,
        handlers = {
          function(config)
            mason_nvim_dap.default_setup(config)
          end,
          python = function(config)
            mason_nvim_dap.default_setup(config)

            local ok, dap_python = pcall(require, "dap-python")
            if not ok then
              return
            end

            local success, debugpy = pcall(registry.get_package, "debugpy")
            if not success then
              return
            end

            local install_path = debugpy:get_install_path()
            local python_path = install_path .. "/venv/bin/python"
            dap_python.setup(python_path)
          end,
        },
      })

      local ok, dap_go = pcall(require, "dap-go")
      if ok then
        dap_go.setup()
      end

      --------------------------------------
      --- clang
      --------------------------------------
      dap.configurations.c = {
        {
          name = "Launch file",
          type = "codelldb",
          request = "launch",
          program = function()
            return vim.fn.input("Path to executable: ", vim.fn.getcwd() .. "/", "file") -- select compiled files
          end,
          cwd = "${workspaceFolder}",
          stopOnEntry = false,
        },
      }

      --------------------------------------
      --- c++
      --------------------------------------
      dap.configurations.cpp = dap.configurations.c

      --------------------------------------
      --- python
      --------------------------------------
      dap.configurations.python = dap.configurations.python or {
        {
          type = "python",
          request = "launch",
          name = "Launch file",
          program = "${file}",
          justMyCode = false,
        },
      }
    end,
  },
}

return {
  {
    "nvim-neotest/neotest",
    dependencies = {
      "nvim-lua/plenary.nvim",
      "nvim-treesitter/nvim-treesitter",
      "nvim-neotest/nvim-nio",
      "antoinemadec/FixCursorHold.nvim",
      "nvim-neotest/neotest-python",
      "nvim-neotest/neotest-go",
      "stevanmilic/neotest-scala",
      "rouge8/neotest-rust",
    },
    keys = function()
      local neotest = require("neotest")
      return {
        { "<leader>tt", function() neotest.run.run() end, desc = "Test nearest" },
        { "<leader>tT", function() neotest.run.run(vim.fn.getcwd()) end, desc = "Test workspace" },
        { "<leader>tf", function() neotest.run.run(vim.fn.expand("%")) end, desc = "Test file" },
        { "<leader>ts", function() neotest.summary.toggle() end, desc = "Toggle summary" },
        { "<leader>to", function() neotest.output.open({ enter = true }) end, desc = "Show output" },
        { "<leader>tO", function() neotest.output_panel.toggle() end, desc = "Toggle output panel" },
        { "<leader>tS", function() neotest.run.stop() end, desc = "Stop test" },
        { "<leader>td", function() neotest.run.run({ strategy = "dap" }) end, desc = "Debug nearest" },
      }
    end,
    config = function()
      local neotest = require("neotest")
      neotest.setup({
        adapters = {
          require("neotest-python")({
            runner = "pytest",
            dap = { justMyCode = false },
          }),
          require("neotest-go")({
            experimental = {
              test_table = true,
            },
          }),
          require("neotest-scala")({
            args = { "test" },
          }),
          require("neotest-rust")({
            args = { "--nocapture" },
          }),
        },
        diagnostic = { enabled = true },
        quickfix = {
          enabled = true,
          open = function()
            if not require("neotest.utils").is_test_suite_running() then
              vim.cmd("copen")
            end
          end,
        },
        running = {
          concurrent = true,
        },
        summary = {
          open = "botright vsplit | vertical resize 40",
        },
      })
    end,
  },
}

